PyTypeObject* DoInitWrapperPrimitiveComponent(const UClass* InClass, PyTypeObject* InSuperType, PyObject* InSuperTypes)
{
	if (InClass == nullptr)
	{
		return nullptr;
	}

	if (FUPyWrapperTypeRegistry::Get().HasWrappedClassType(InClass))
	{
		return const_cast<PyTypeObject*>(FUPyWrapperTypeRegistry::Get().GetWrappedClassType(InClass));
	}

	PyTypeObject* PyType = &UPyWrapperPrimitiveComponentType;
	PyType->tp_flags = Py_TPFLAGS_DEFAULT | Py_TPFLAGS_BASETYPE;
	PyType->tp_base = InSuperType != nullptr ? InSuperType : &UPyWrapperObjectType;
	PyType->tp_bases = InSuperTypes;
	PyType->tp_methods = FUPyWrapperPrimitiveComponentPyMethodDefs;
	PyType->tp_getset = FUPyWrapperPrimitiveComponentGetSets;

	if (PyType_Ready(PyType) == 0)
	{
		FUPyWrapperTypeRegistry::Get().RegisterWrappedClassType(InClass, PyType);
		return PyType;
	}

	return nullptr;
}

void InitializeUPyWrapperPrimitiveComponent(UPyGenUtil::FNativePythonModule& ModuleInfo)
{
	FUPyWrapperTypeRegistry::Get().RegisterAutoWrappedClassCreateFunc(UPrimitiveComponent::StaticClass(), DoInitWrapperPrimitiveComponent);
}

FUPyWrapperPrimitiveComponent* UPyIsPrimitiveComponent(PyObject* InSelf)
{
	if (InSelf && PyObject_IsInstance(InSelf, (PyObject*)&UPyWrapperPrimitiveComponentType))
	{
		return (FUPyWrapperPrimitiveComponent*)InSelf;
	}
	return nullptr;
}

namespace UPyConversion
{
	FUPyConversionResult Nativize(PyObject* PyObj, UPrimitiveComponent*& OutVal, const ESetErrorState SetErrorState)
	{
		if (FUPyWrapperPrimitiveComponent* PyPrimitiveComponent = UPyIsPrimitiveComponent(PyObj))
		{
			if (!FUPyWrapperObject::ValidateInternalState(PyPrimitiveComponent))
			{
				return FUPyConversionResult::Failure();
			}

			OutVal = PyPrimitiveComponent->ValuePtr();
			return FUPyConversionResult::Success();
		}

		UPYCONVERSION_RETURN(FUPyConversionResult::Failure(), TEXT("Nativize"), *FString::Printf(TEXT("Cannot nativize '%s' as 'UPrimitiveComponent'"), *UPyUtil::GetFriendlyTypename(PyObj)));
	}
}
